1	/**
2	 * DesignerModeTabs.tsx
3	 *
4	 * 36px mode-tab bar that sits above the toolbar in the Designer layout.
5	 * Contains Graphic / Dashboard / Report tabs and a File dropdown menu.
6	 *
7	 * Layout:
8	 *   ┌──────────────┬──────────────┬──────────────┬─────────────────────────────┐
9	 *   │  ◆ Graphic   │  ▦ Dashboard │  📄 Report   │                  [File ▾]   │
10	 *   └──────────────┴──────────────┴──────────────┴─────────────────────────────┘
11	 */
12	
13	import { useEffect, useRef, useState } from "react";
14	import { useSceneStore } from "../../store/designer";
15	import { useDesignerPermissions } from "../../shared/hooks/usePermission";
16	
17	// ---------------------------------------------------------------------------
18	// Props
19	// ---------------------------------------------------------------------------
20	
21	export interface DesignerModeTabsProps {
22	  canPublish?: boolean;
23	  onSave?: () => void;
24	  onShowVersionHistory?: () => void;
25	  onValidateBindings?: () => void;
26	  onImport?: () => void;
27	  onExport?: () => void;
28	  onExportSvg?: () => void;
29	  onPublish?: () => void;
30	  onNew?: () => void;
31	  onOpen?: () => void;
32	  onProperties?: () => void;
33	  onRename?: () => void;
34	}
35	
36	// ---------------------------------------------------------------------------
37	// Tab definitions
38	// ---------------------------------------------------------------------------
39	
40	type DesignMode = "graphic" | "dashboard" | "report";
41	
42	interface TabDef {
43	  mode: DesignMode;
44	  icon: string;
45	  label: string;
46	}
47	
48	const TABS: TabDef[] = [
49	  { mode: "graphic", icon: "◆", label: "Graphic" },
50	  { mode: "dashboard", icon: "▦", label: "Dashboard" },
51	  { mode: "report", icon: "📄", label: "Report" },
52	];
53	
54	// ---------------------------------------------------------------------------
55	// File menu item type
56	// ---------------------------------------------------------------------------
57	
58	interface MenuItemDef {
59	  label: string;
60	  shortcut?: string;
61	  action?: () => void;
62	  accent?: boolean;
63	  divider?: false;
64	}
65	
66	interface MenuDividerDef {
67	  divider: true;
68	}
69	
70	type MenuItem = MenuItemDef | MenuDividerDef;
71	
72	// ---------------------------------------------------------------------------
73	// Component
74	// ---------------------------------------------------------------------------
75	
76	export default function DesignerModeTabs({
77	  canPublish = false,
78	  onSave,
79	  onShowVersionHistory,
80	  onValidateBindings,
81	  onImport,
82	  onExport,
83	  onExportSvg,
84	  onPublish,
85	  onNew,
86	  onOpen,
87	  onProperties,
88	  onRename,
89	}: DesignerModeTabsProps) {
90	  const designMode = useSceneStore((s) => s.designMode);
91	  const setDesignMode = useSceneStore((s) => s.setDesignMode);
92	  const perms = useDesignerPermissions();
93	
94	  const [fileMenuOpen, setFileMenuOpen] = useState(false);
95	  const menuRef = useRef<HTMLDivElement>(null);
96	
97	  // Close file menu on outside click
