1	/**
2	 * DesignerTabBar.tsx
3	 *
4	 * Horizontal tab bar placed between the toolbar and the canvas area.
5	 * Shows one tab per open graphic. Supports:
6	 *   - Modified dot (●) when isModified
7	 *   - Close button (×)
8	 *   - Active tab highlight
9	 *   - Horizontal scroll when tabs overflow
10	 *   - Right-click context menu: Close, Close Others, Close All, Copy Name
11	 */
12	
13	import React, { useRef, useCallback, useEffect, useState } from "react";
14	import type { DesignerTab } from "../../store/designer/tabStore";
15	import { useContextMenu } from "../../shared/hooks/useContextMenu";
16	import ContextMenu from "../../shared/components/ContextMenu";
17	
18	// ---------------------------------------------------------------------------
19	// Props
20	// ---------------------------------------------------------------------------
21	
22	interface DesignerTabBarProps {
23	  tabs: DesignerTab[];
24	  activeTabId: string | null;
25	  onSwitchTab: (tabId: string) => void;
26	  onCloseTab: (tabId: string) => void;
27	  onCloseOthers: (keepTabId: string) => void;
28	  onCloseAll: () => void;
29	  onRenameTab: (tabId: string) => void;
30	}
31	
32	// ---------------------------------------------------------------------------
33	// Helpers
34	// ---------------------------------------------------------------------------
35	
36	function truncate(name: string, max = 20): string {
37	  if (name.length <= max) return name;
38	  return name.slice(0, max) + "\u2026";
39	}
40	
41	/** Build the display label for a tab. Group sub-tabs show "Graphic › Group" (truncated). */
42	function tabLabel(tab: DesignerTab): string {
43	  if (tab.type === "group" && tab.groupName) {
44	    const g =
45	      tab.graphicName.length > 12
46	        ? tab.graphicName.slice(0, 12) + "\u2026"
47	        : tab.graphicName;
48	    const n =
49	      tab.groupName.length > 12
50	        ? tab.groupName.slice(0, 12) + "\u2026"
51	        : tab.groupName;
52	    return `${g} \u203a ${n}`;
53	  }
54	  return truncate(tab.graphicName);
55	}
56	
57	// ---------------------------------------------------------------------------
58	// Single tab item
59	// ---------------------------------------------------------------------------
60	
61	interface TabItemProps {
62	  tab: DesignerTab;
63	  active: boolean;
64	  onSwitch: () => void;
65	  onClose: () => void;
66	  onCloseOthers: () => void;
67	  onCloseAll: () => void;
68	  onRename: () => void;
69	}
70	
71	function TabItem({
72	  tab,
73	  active,
74	  onSwitch,
75	  onClose,
76	  onCloseOthers,
77	  onCloseAll,
78	  onRename,
79	}: TabItemProps) {
80	  const [hovered, setHovered] = useState(false);
81	
82	  const displayLabel = tabLabel(tab);
83	  const fullTitle =
84	    tab.type === "group" && tab.groupName
85	      ? `${tab.graphicName} › ${tab.groupName}`
86	      : tab.graphicName;
87	
88	  const handleCopyName = useCallback(() => {
89	    navigator.clipboard.writeText(fullTitle).catch(() => {
90	      /* best-effort */
91	    });
92	  }, [fullTitle]);
93	
94	  const handleClose = useCallback(
95	    (e: React.MouseEvent) => {
96	      e.stopPropagation();
97	      onClose();
98	    },
99	    [onClose],
100	  );
101	
102	  const { menuState, handleContextMenu, closeMenu } = useContextMenu();
103	
104	  const menuItems = [
105	    {
106	      label: "Rename…",
107	      onClick: () => {
108	        closeMenu();
109	        onRename();
110	      },
111	    },
112	    {
113	      label: "Close",
114	      divider: true,
115	      onClick: () => {
116	        closeMenu();
117	        onClose();
118	      },
119	    },
120	    {
121	      label: "Close Others",
122	      onClick: () => {
123	        closeMenu();
124	        onCloseOthers();
125	      },
126	    },
127	    {
128	      label: "Close All",
129	      onClick: () => {
130	        closeMenu();
131	        onCloseAll();
132	      },
133	    },
134	    {
135	      label: "Copy Name",
136	      divider: true,
137	      onClick: () => {
138	        closeMenu();
139	        handleCopyName();
140	      },
141	    },
142	  ];
143	
144	  return (
145	    <>
146	      <div
147	        role="tab"
148	        aria-selected={active}
149	        title={fullTitle}
150	        onMouseEnter={() => setHovered(true)}
151	        onMouseLeave={() => setHovered(false)}
152	        onClick={onSwitch}
153	        onContextMenu={handleContextMenu}
154	        style={{
155	          display: "flex",
156	          alignItems: "center",
157	          gap: 4,
158	          padding: "0 10px 0 12px",
159	          height: "100%",
160	          flexShrink: 0,
161	          cursor: "pointer",
162	          whiteSpace: "nowrap",
163	          fontSize: 12,
164	          fontWeight: active ? 600 : 400,
165	          color: active ? "var(--io-text-primary)" : "var(--io-text-secondary)",
166	          background: active
167	            ? "var(--io-surface-elevated)"
168	            : hovered
169	              ? "var(--io-surface-elevated)"
170	              : "var(--io-surface)",
