1	/**
2	 * DesignerStatusBar.tsx
3	 *
4	 * 28px status bar at the very bottom of the Designer area.
5	 * Segments (left-to-right):
6	 *   1. WebSocket connection status
7	 *   2. Point binding summary (click to validate)
8	 *   3. Grid size (click to cycle)
9	 *   4. Zoom level (click to show presets)
10	 *   5. Mode indicator (Edit / Test Mode / Read-Only)
11	 *   6. Auto-save indicator (right-aligned)
12	 */
13	
14	import React, { useEffect, useRef, useState } from "react";
15	import { useSceneStore, useUiStore } from "../../store/designer";
16	import type {
17	  GraphicDocument,
18	  SymbolInstance,
19	  DisplayElement,
20	  SceneNode,
21	} from "../../shared/types/graphics";
22	
23	// ---------------------------------------------------------------------------
24	// Props
25	// ---------------------------------------------------------------------------
26	
27	export interface DesignerStatusBarProps {
28	  wsConnected?: boolean;
29	  readOnly?: boolean;
30	  lastAutoSave?: number | null;
31	  onValidateBindings?: () => void;
32	}
33	
34	// ---------------------------------------------------------------------------
35	// Helpers
36	// ---------------------------------------------------------------------------
37	
38	const GRID_CYCLE = [4, 8, 10, 16, 32] as const;
39	const ZOOM_PRESETS = [25, 50, 75, 100, 150, 200, 400] as const;
40	
41	/**
42	 * Walk all nodes in the document tree and count bound DisplayElement and
43	 * SymbolInstance bindings.
44	 */
45	function countBindings(doc: GraphicDocument): {
46	  bound: number;
47	  unresolved: number;
48	} {
49	  let bound = 0;
50	
51	  function walkNodes(nodes: SceneNode[]) {
52	    for (const node of nodes) {
53	      if (node.type === "display_element") {
54	        const de = node as DisplayElement;
55	        if (de.binding?.pointId) bound++;
56	      } else if (node.type === "symbol_instance") {
57	        const si = node as SymbolInstance;
58	        if (si.stateBinding?.pointId) bound++;
59	        // Also recurse into children of the symbol instance
60	        if (si.children && si.children.length > 0) {
61	          walkNodes(si.children);
62	        }
63	      }
64	      // Recurse for group / document children
65	      if (
66	        "children" in node &&
67	        Array.isArray((node as { children?: SceneNode[] }).children)
68	      ) {
69	        const children = (node as { children?: SceneNode[] }).children;
70	        if (children && node.type !== "symbol_instance") {
71	          walkNodes(children);
72	        }
73	      }
74	    }
75	  }
76	
77	  walkNodes(doc.children);
78	  // For now, we have no OPC point list to compare against, so unresolved = 0
79	  return { bound, unresolved: 0 };
80	}
81	
82	/**
83	 * Format epoch ms as relative time string.
84	 */
85	function formatRelativeTime(epochMs: number): string {
86	  const diffSec = Math.floor((Date.now() - epochMs) / 1000);
87	  if (diffSec < 60) return "just now";
88	  const diffMin = Math.floor(diffSec / 60);
89	  if (diffMin < 60) return `${diffMin}m ago`;
90	  const diffHr = Math.floor(diffMin / 60);
91	  return `${diffHr}h ago`;
92	}
93	
94	// ---------------------------------------------------------------------------
95	// Segment divider
96	// ---------------------------------------------------------------------------
97	
98	function Divider() {
99	  return (
100	    <div
101	      style={{
102	        width: 1,
103	        height: 16,
104	        background: "var(--io-border)",
105	        flexShrink: 0,
106	      }}
107	    />
108	  );
109	}
110	
111	// ---------------------------------------------------------------------------
112	// Component
113	// ---------------------------------------------------------------------------
114	
115	export default function DesignerStatusBar({
116	  wsConnected = true,
117	  readOnly = false,
118	  lastAutoSave = null,
119	  onValidateBindings,
120	}: DesignerStatusBarProps) {
121	  const doc = useSceneStore((s) => s.doc);
122	  const gridSize = useUiStore((s) => s.gridSize);
123	  const setGrid = useUiStore((s) => s.setGrid);
124	  const gridVisible = useUiStore((s) => s.gridVisible);
125	  const zoom = useUiStore((s) => s.viewport.zoom);
126	  const zoomTo = useUiStore((s) => s.zoomTo);
127	  const testMode = useUiStore((s) => s.testMode);
128	  const testModePaused = useUiStore((s) => s.testModePaused);
129	  const setTestModePaused = useUiStore((s) => s.setTestModePaused);
130	
131	  // Zoom dropdown visibility
132	  const [zoomOpen, setZoomOpen] = useState(false);
133	  const zoomRef = useRef<HTMLDivElement>(null);
134	
135	  // Relative time ticker for auto-save label
136	  const [, setTick] = useState(0);
137	  useEffect(() => {
138	    const id = setInterval(() => setTick((t) => t + 1), 30_000);
139	    return () => clearInterval(id);
140	  }, []);
141	
142	  // Close zoom dropdown on outside click
143	  useEffect(() => {
144	    if (!zoomOpen) return;
145	    function handleClick(e: MouseEvent) {
146	      if (zoomRef.current && !zoomRef.current.contains(e.target as Node)) {
