import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useTabStore } from "../../store/designer/tabStore";

export default function DesignerHome() {
  const navigate = useNavigate();

  // If tabs are already open, redirect to the active one instead of showing home.
  // This handles: clicking the Designer nav item when work is in progress.
  useEffect(() => {
    const tabs = useTabStore.getState().tabs;
    if (tabs.length === 0) return;
    const activeId = useTabStore.getState().activeTabId;
    const targetTab =
      tabs.find((t) => t.id === activeId) ?? tabs[tabs.length - 1];
    if (!targetTab) return;
    if (!targetTab.graphicId.startsWith("new-")) {
      navigate(`/designer/graphics/${targetTab.graphicId}/edit`, {
        replace: true,
      });
    } else {
      navigate("/designer/graphics/new", { replace: true });
    }
  }, [navigate]);

  return (
    <div
      style={{
        height: "100%",
        background: "var(--io-surface-secondary)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: 12,
        }}
      >
        <div
          style={{
            fontSize: 13,
            color: "var(--io-text-muted)",
            marginBottom: 4,
            letterSpacing: "0.03em",
          }}
        >
          Designer
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <button
            onClick={() => navigate("/designer/graphics/new")}
            style={{
              padding: "9px 22px",
              background: "var(--io-accent)",
              color: "var(--io-accent-foreground)",
              border: "none",
              borderRadius: "var(--io-radius)",
              fontSize: 13,
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            New
          </button>
          <button
            onClick={() => navigate("/designer/graphics")}
            style={{
              padding: "9px 22px",
              background: "transparent",
              color: "var(--io-text-secondary)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              fontSize: 13,
              fontWeight: 500,
              cursor: "pointer",
            }}
          >
            Open Existing
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * Designer page — main orchestrator.
 *
 * Route: /designer/graphics/:id/edit  (edit existing)
 *        /designer/graphics/new         (create new)
 *
 * Layout:
 *   ┌─────────────────────────────────────────────────────┐
 *   │  DesignerToolbar (44px)                             │
 *   ├──────────┬──────────────────────────────────────────┤
 *   │  Left    │  DesignerCanvas (flex 1)                 │ Right
 *   │  Palette │                                          │ Panel
 *   │  240px   │                                          │ 300px
 *   └──────────┴──────────────────────────────────────────┘
 *
 * State management: Zustand (sceneStore, historyStore, uiStore)
 * API: graphicsApi from ../../api/graphics
 */

import React, { useEffect, useState, useCallback, useRef } from "react";
import { useParams, useNavigate, useLocation } from "react-router-dom";
import {
  useSceneStore,
  useHistoryStore,
  useTabStore,
  useLibraryStore,
  MAX_TABS,
} from "../../store/designer";
import { useUiStore } from "../../store/designer/uiStore";
import { graphicsApi } from "../../api/graphics";
import { pointsApi } from "../../api/points";
import type {
  SceneNode,
  GraphicDocument,
  DisplayElement,
  SymbolInstance,
} from "../../shared/types/graphics";
import { wsManager } from "../../shared/hooks/useWebSocket";
import { useDesignerPermissions } from "../../shared/hooks/usePermission";
import { showToast } from "../../shared/components/Toast";
import { ErrorBoundary } from "../../shared/components/ErrorBoundary";
import DesignerToolbar from "./DesignerToolbar";
import DesignerModeTabs from "./DesignerModeTabs";
import DesignerStatusBar from "./DesignerStatusBar";
import DesignerLeftPalette from "./DesignerLeftPalette";
import DesignerRightPanel from "./DesignerRightPanel";
import DesignerCanvas, { getNodeBounds } from "./DesignerCanvas";
import DesignerTabBar from "./DesignerTabBar";
import VersionHistoryDialog from "./components/VersionHistoryDialog";
import { PublishConfirmDialog } from "../../shared/components/versioning";
import { SaveConfirmDialog } from "../../shared/components/versioning/SaveConfirmDialog";
import ValidateBindingsDialog from "./components/ValidateBindingsDialog";
import IographicImportWizard from "./components/IographicImportWizard";
import IographicExportDialog from "./components/IographicExportDialog";
import CanvasPropertiesDialog from "./components/CanvasPropertiesDialog";
import TabClosePrompt from "./components/TabClosePrompt";
import { ConfirmDialog } from "../../shared/components/ConfirmDialog";
import {
  AspectPreset,
  ASPECT_PRESETS,
  ChainLinkIcon,
} from "./components/canvasPresets";

// ---------------------------------------------------------------------------
// New Graphic dialog
// ---------------------------------------------------------------------------

interface NewGraphicDialogProps {
  onConfirm: (
    name: string,
    mode: "graphic" | "dashboard" | "report",
    width: number,
    height: number,
    autoHeight: boolean,
    scope: "console" | "process" | null,
  ) => void;
  onCancel: () => void;
  initialMode?: "graphic" | "dashboard" | "report";
}

// Defaults per mode
const MODE_DEFAULTS: Record<
  "graphic" | "dashboard" | "report",
  { width: number; height: number; autoHeight: boolean }
> = {
  graphic: { width: 1920, height: 1080, autoHeight: false },
  dashboard: { width: 1920, height: 1080, autoHeight: false },
  report: { width: 794, height: 1123, autoHeight: true },
};

// ---------------------------------------------------------------------------
// NewGraphicDialog
// ---------------------------------------------------------------------------

function NewGraphicDialog({
  onConfirm,
  onCancel,
  initialMode = "graphic",
}: NewGraphicDialogProps) {
  const defaultName =
    initialMode === "dashboard"
      ? "Untitled Dashboard"
      : initialMode === "report"
        ? "Untitled Report"
        : "Untitled Graphic";
  const [name, setName] = useState(defaultName);
  const [mode, setMode] = useState<"graphic" | "dashboard" | "report">(
    initialMode,
  );
  const [scope, setScope] = useState<"console" | "process">("console");
  const [width, setWidth] = useState<number>(MODE_DEFAULTS[initialMode].width);
  const [height, setHeight] = useState<number>(
    MODE_DEFAULTS[initialMode].height,
  );
  const [autoHeight, setAutoHeight] = useState<boolean>(
    MODE_DEFAULTS[initialMode].autoHeight,
  );
  const [proportionalLock, setProportionalLock] = useState(false);
  const [activePreset, setActivePreset] = useState<string | null>("1080p");

  // When mode changes, reset to that mode's defaults
  function handleModeChange(newMode: "graphic" | "dashboard" | "report") {
    setMode(newMode);
    const defaults = MODE_DEFAULTS[newMode];
    setWidth(defaults.width);
    setHeight(defaults.height);
    setAutoHeight(defaults.autoHeight);
    // Check if the new defaults match a preset
    const matching = ASPECT_PRESETS.find(
      (p) => p.width === defaults.width && p.height === defaults.height,
    );
    setActivePreset(matching ? matching.label : null);
    setProportionalLock(false);
  }

  function applyPreset(preset: AspectPreset) {
    setWidth(preset.width);
    setHeight(preset.height);
    setActivePreset(preset.label);
  }

  function handleWidthChange(raw: string) {
    const val = parseInt(raw, 10);
    if (isNaN(val)) return;
    if (proportionalLock && height > 0 && width > 0) {
      const newH = Math.round(val * (height / width));
      setHeight(newH);
    }
    setWidth(val);
    // Clear active preset if no match
    const matching = ASPECT_PRESETS.find((p) => {
      const newH =
        proportionalLock && height > 0 && width > 0
          ? Math.round(val * (height / width))
          : height;
      return p.width === val && p.height === newH;
    });
    setActivePreset(matching ? matching.label : null);
  }

  function handleHeightChange(raw: string) {
    const val = parseInt(raw, 10);
    if (isNaN(val)) return;
    if (proportionalLock && width > 0 && height > 0) {
      const newW = Math.round(val * (width / height));
      setWidth(newW);
    }
    setHeight(val);
    const matching = ASPECT_PRESETS.find((p) => {
      const newW =
        proportionalLock && width > 0 && height > 0
          ? Math.round(val * (width / height))
          : width;
      return p.width === newW && p.height === val;
    });
    setActivePreset(matching ? matching.label : null);
  }

  function clampWidth(val: number): number {
    return Math.max(320, Math.min(20000, val));
  }
  function clampHeight(val: number): number {
    return Math.max(240, Math.min(15000, val));
  }

  function handleWidthBlur() {
    setWidth((w) => clampWidth(w));
  }
  function handleHeightBlur() {
    setHeight((h) => clampHeight(h));
  }

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const trimmed = name.trim();
    if (!trimmed) return;
    onConfirm(
      trimmed,
      mode,
      clampWidth(width),
      clampHeight(height),
      autoHeight,
      mode === "graphic" ? scope : null,
    );
  }

  const visiblePresets = ASPECT_PRESETS.filter(
    (p) => !p.reportOnly || mode === "report",
  );

  const inputStyle: React.CSSProperties = {
    width: "100%",
    padding: "6px 8px",
    background: "var(--io-surface)",
    border: "1px solid var(--io-border)",
    borderRadius: "var(--io-radius)",
    color: "var(--io-text-primary)",
    fontSize: 13,
    outline: "none",
    boxSizing: "border-box",
  };

  const labelStyle: React.CSSProperties = {
    display: "block",
    fontSize: 11,
    fontWeight: 600,
    color: "var(--io-text-muted)",
    textTransform: "uppercase",
    letterSpacing: "0.05em",
    marginBottom: 4,
  };

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "rgba(0,0,0,0.6)",
      }}
    >
      <form
        onSubmit={handleSubmit}
        style={{
          background: "var(--io-surface-elevated)",
          border: "1px solid var(--io-border)",
          borderRadius: "var(--io-radius)",
          padding: 24,
          width: 440,
          maxWidth: "92%",
          display: "flex",
          flexDirection: "column",
          gap: 16,
        }}
      >
        <div
          style={{
            fontSize: 15,
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          {mode === "dashboard"
            ? "New Dashboard"
            : mode === "report"
              ? "New Report"
              : "New Graphic"}
        </div>

        {/* Name */}
        <div>
          <label style={labelStyle}>Name</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            autoFocus
            style={inputStyle}
          />
        </div>

        {/* Type / Mode */}
        <div>
          <label style={labelStyle}>Type</label>
          <div style={{ display: "flex", gap: 8 }}>
            {(["graphic", "dashboard", "report"] as const).map((m) => (
              <button
                key={m}
                type="button"
                onClick={() => handleModeChange(m)}
                style={{
                  flex: 1,
                  padding: "6px 0",
                  background:
                    mode === m ? "var(--io-accent)" : "var(--io-surface)",
                  color:
                    mode === m
                      ? "var(--io-accent-foreground)"
                      : "var(--io-text-secondary)",
                  border: "1px solid var(--io-border)",
                  borderRadius: "var(--io-radius)",
                  fontSize: 12,
                  fontWeight: mode === m ? 600 : 400,
                  cursor: "pointer",
                  textTransform: "capitalize",
                }}
              >
                {m}
              </button>
            ))}
          </div>
        </div>

        {/* Scope — only relevant for graphic type */}
        {mode === "graphic" && (
          <div>
            <label style={labelStyle}>Module</label>
            <div style={{ display: "flex", gap: 8 }}>
              {(["console", "process"] as const).map((s) => (
                <button
                  key={s}
                  type="button"
                  onClick={() => setScope(s)}
                  style={{
                    flex: 1,
                    padding: "6px 0",
                    background:
                      scope === s ? "var(--io-accent)" : "var(--io-surface)",
                    color:
                      scope === s
                        ? "var(--io-accent-foreground)"
                        : "var(--io-text-secondary)",
                    border: "1px solid var(--io-border)",
                    borderRadius: "var(--io-radius)",
                    fontSize: 12,
                    fontWeight: scope === s ? 600 : 400,
                    cursor: "pointer",
                    textTransform: "capitalize",
                  }}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Preset chip row */}
        <div>
          <label style={labelStyle}>Canvas Preset</label>
          <div
            style={{
              overflowX: "auto",
              display: "flex",
              gap: 6,
              flexWrap: "nowrap",
              paddingBottom: 2,
            }}
          >
            {visiblePresets.map((preset) => {
              const isActive = activePreset === preset.label;
              return (
                <button
                  key={preset.label}
                  type="button"
                  onClick={() => applyPreset(preset)}
                  title={`${preset.width} \u00d7 ${preset.height}`}
                  style={{
                    flexShrink: 0,
                    padding: "3px 8px",
                    fontSize: 11,
                    fontWeight: isActive ? 600 : 400,
                    background: isActive
                      ? "var(--io-accent)"
                      : "var(--io-surface)",
                    color: isActive
                      ? "var(--io-accent-foreground)"
                      : "var(--io-text-secondary)",
                    border: "1px solid var(--io-border)",
                    borderRadius: "calc(var(--io-radius) * 2)",
                    cursor: "pointer",
                    whiteSpace: "nowrap",
                  }}
                >
                  {preset.label}
                </button>
              );
            })}
          </div>
        </div>

        {/* Width / Height inputs with proportional lock */}
        <div>
          <label style={labelStyle}>
            {mode === "report" ? "Min. Height" : "Canvas Size"}
          </label>
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            {/* Width */}
            <div style={{ flex: 1 }}>
              <div
                style={{
                  fontSize: 10,
                  color: "var(--io-text-muted)",
                  marginBottom: 2,
                }}
              >
                Width
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                <input
                  type="number"
                  value={width}
                  min={320}
                  max={20000}
                  onChange={(e) => handleWidthChange(e.target.value)}
                  onBlur={handleWidthBlur}
                  style={{ ...inputStyle, width: "100%" }}
                />
                <span
                  style={{
                    fontSize: 11,
                    color: "var(--io-text-muted)",
                    flexShrink: 0,
                  }}
                >
                  px
                </span>
              </div>
            </div>

            {/* Proportional lock toggle */}
            <button
              type="button"
              onClick={() => setProportionalLock((l) => !l)}
              title={
                proportionalLock ? "Unlock proportions" : "Lock proportions"
              }
              style={{
                flexShrink: 0,
                width: 28,
                height: 28,
                marginTop: 16,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                background: proportionalLock
                  ? "var(--io-accent)"
                  : "var(--io-surface)",
                color: proportionalLock
                  ? "var(--io-accent-foreground)"
                  : "var(--io-text-muted)",
                border: "1px solid var(--io-border)",
                borderRadius: "var(--io-radius)",
                cursor: "pointer",
                padding: 0,
              }}
            >
              <ChainLinkIcon locked={proportionalLock} />
            </button>

            {/* Height */}
            <div style={{ flex: 1 }}>
              <div
                style={{
                  fontSize: 10,
                  color: "var(--io-text-muted)",
                  marginBottom: 2,
                }}
              >
                {mode === "report" ? "Min. Height" : "Height"}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                <input
                  type="number"
                  value={height}
                  min={240}
                  max={15000}
                  onChange={(e) => handleHeightChange(e.target.value)}
                  onBlur={handleHeightBlur}
                  style={{ ...inputStyle, width: "100%" }}
                />
                <span
                  style={{
                    fontSize: 11,
                    color: "var(--io-text-muted)",
                    flexShrink: 0,
                  }}
                >
                  px
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Buttons */}
        <div
          style={{
            display: "flex",
            justifyContent: "flex-end",
            gap: 8,
            marginTop: 4,
          }}
        >
          <button
            type="button"
            onClick={onCancel}
            style={{
              padding: "6px 14px",
              background: "transparent",
              color: "var(--io-text-secondary)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={!name.trim()}
            style={{
              padding: "6px 14px",
              background: name.trim()
                ? "var(--io-accent)"
                : "var(--io-surface-elevated)",
              color: name.trim()
                ? "var(--io-accent-foreground)"
                : "var(--io-text-muted)",
              border: "none",
              borderRadius: "var(--io-radius)",
              fontSize: 12,
              fontWeight: 600,
              cursor: name.trim() ? "pointer" : "not-allowed",
            }}
          >
            Create
          </button>
        </div>
      </form>
    </div>
  );
}

// ---------------------------------------------------------------------------
// RenameDialog
// ---------------------------------------------------------------------------

interface RenameDialogProps {
  currentName: string;
  onConfirm: (newName: string) => void;
  onCancel: () => void;
}

function RenameDialog({ currentName, onConfirm, onCancel }: RenameDialogProps) {
  const [name, setName] = useState(currentName);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const trimmed = name.trim();
    if (!trimmed) return;
    onConfirm(trimmed);
  }

  const canSubmit = name.trim().length > 0 && name.trim() !== currentName;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "rgba(0,0,0,0.6)",
      }}
      onMouseDown={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <form
        onSubmit={handleSubmit}
        style={{
          background: "var(--io-surface-elevated)",
          border: "1px solid var(--io-border)",
          borderRadius: "var(--io-radius)",
          padding: 24,
          width: 360,
          maxWidth: "92%",
          display: "flex",
          flexDirection: "column",
          gap: 16,
        }}
      >
        <div
          style={{
            fontSize: 15,
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          Rename
        </div>
        <div>
          <label
            style={{
              display: "block",
              fontSize: 11,
              fontWeight: 600,
              color: "var(--io-text-muted)",
              textTransform: "uppercase",
              letterSpacing: "0.05em",
              marginBottom: 4,
            }}
          >
            Name
          </label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            autoFocus
            style={{
              width: "100%",
              padding: "6px 8px",
              background: "var(--io-surface)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              color: "var(--io-text-primary)",
              fontSize: 13,
              outline: "none",
              boxSizing: "border-box",
            }}
          />
        </div>
        <div
          style={{
            display: "flex",
            justifyContent: "flex-end",
            gap: 8,
            marginTop: 4,
          }}
        >
          <button
            type="button"
            onClick={onCancel}
            style={{
              padding: "6px 14px",
              background: "transparent",
              color: "var(--io-text-secondary)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={!canSubmit}
            style={{
              padding: "6px 14px",
              background: canSubmit
                ? "var(--io-accent)"
                : "var(--io-surface-elevated)",
              color: canSubmit
                ? "var(--io-accent-foreground)"
                : "var(--io-text-muted)",
              border: "none",
              borderRadius: "var(--io-radius)",
              fontSize: 12,
              fontWeight: 600,
              cursor: canSubmit ? "pointer" : "not-allowed",
            }}
          >
            Rename
          </button>
        </div>
      </form>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Resizable divider
// ---------------------------------------------------------------------------

interface DividerProps {
  onDrag: (dx: number) => void;
  /** Which panel edge this handle sits on. Controls absolute positioning. */
  side: "left" | "right";
}

// Resize handle rendered *inside* the panel container (position absolute),
// matching the ConsolePalette pattern. No flex-flow footprint → zero gap.
function VerticalDivider({ onDrag, side }: DividerProps) {
  const startX = useRef(0);
  const active = useRef(false);

  function handleMouseDown(e: React.MouseEvent) {
    e.preventDefault();
    active.current = true;
    startX.current = e.clientX;

    const onMove = (ev: MouseEvent) => {
      if (!active.current) return;
      const dx = ev.clientX - startX.current;
      startX.current = ev.clientX;
      onDrag(dx);
    };
    const onUp = () => {
      active.current = false;
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
    };
    document.addEventListener("mousemove", onMove);
    document.addEventListener("mouseup", onUp);
  }

  return (
    <div
      draggable={false}
      onDragStart={(e) => e.preventDefault()}
      onMouseDown={handleMouseDown}
      style={{
        position: "absolute",
        top: 0,
        ...(side === "left" ? { right: 0 } : { left: 0 }),
        width: 5,
        height: "100%",
        cursor: "col-resize",
        background: "transparent",
        zIndex: 10,
        transition: "background 0.15s",
        userSelect: "none",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.background = "var(--io-accent)";
        e.currentTarget.style.opacity = "0.3";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.background = "transparent";
        e.currentTarget.style.opacity = "1";
      }}
    />
  );
}

